#!/usr/bin/env python3
"""
quasicrystal_hamiltonian.py -- one file, one artwork.

Generates ab_hamiltonian_rainbow_wide_glow.svg: a single Hamiltonian cycle
on an Ammann-Beenker tiling, built exactly per Singh, Lloyd & Flicker,
"Hamiltonian Cycles on Ammann-Beenker Tilings", PRX 14, 031005 (2024)
(https://journals.aps.org/prx/abstract/10.1103/PhysRevX.14.031005).

Pipeline (all arithmetic exact -- integers and Q(sqrt2) fractions):
  1. Substitution generation: 8-rhombus rosette seeded at the central
     8-vertex, three twice-inflations (8 -> 248 -> 8,648 -> 295,352 tiles).
     The decomposition rule (with square chirality variants and the
     half-square straddler pairs on supertile edges) is embedded below as
     data, extracted once from a reference tiling and verified deterministic.
  2. Canonical fully-packed-loop decoration e0, applied per supertile class
     (read originally off the paper's own Fig. 3 vector data), plus the
     edge-strip rule; a small forced matching completes patch-fringe strips.
  3. e1 alternating paths along all closed rings of supertile edges,
     orientations alternating (opposite orientation = point reflection),
     merging every loop they cut and threading the 8-vertices.
  4. The 16-edge star at level 2 with ONE CORNER FOLDED INWARD through the
     central 8-vertex -- the paper's final trick -- then descent to level 0.
  5. Coloring by "generation" (size class of each edge's canonical loop),
     bright same-hue cores, black background, rotated so the folded flat
     side faces down, rendered as raw SVG with round joins/caps (which caps
     every join's reach at the half-width: strands provably never touch,
     since the minimum vertex-to-nonincident-edge distance is sin 45).

Dependencies: Python 3.9+, networkx (pip install networkx).
Runtime: a few minutes; peak RAM ~2 GB.  Output in the working directory.
"""
import math, sys, time
from fractions import Fraction as Fr
from collections import defaultdict

# ============================================================ exact numbers
class R2:
    """Exact p + q*sqrt(2)."""
    __slots__ = ('p', 'q')
    def __init__(self, p=0, q=0):
        self.p = p if isinstance(p, Fr) else Fr(p)
        self.q = q if isinstance(q, Fr) else Fr(q)
    def __add__(s, o): return R2(s.p + o.p, s.q + o.q)
    def __sub__(s, o): return R2(s.p - o.p, s.q - o.q)
    def __neg__(s):    return R2(-s.p, -s.q)
    def __mul__(s, o):
        if isinstance(o, R2):
            return R2(s.p * o.p + 2 * s.q * o.q, s.p * o.q + s.q * o.p)
        return R2(s.p * o, s.q * o)
    def __hash__(self):  return hash((self.p, self.q))
    def __eq__(s, o):    return s.p == o.p and s.q == o.q
    def __float__(s):    return float(s.p) + float(s.q) * math.sqrt(2)
    def sign(s):
        if s.p == 0 and s.q == 0: return 0
        if s.p >= 0 and s.q >= 0: return 1
        if s.p <= 0 and s.q <= 0: return -1
        return (1 if s.p > 0 else -1) * (1 if s.p * s.p > 2 * s.q * s.q else -1)

HALF = R2(0, Fr(1, 2))
E = [(R2(1), R2(0)), (HALF, HALF), (R2(0), R2(1)), (-HALF, HALF)]
M  = [(1, 1, 0, -1), (1, 1, 1, 0), (0, 1, 1, 1), (-1, 0, 1, 1)]
MI = [(-1, 1, 0, -1), (1, -1, 1, 0), (0, 1, -1, 1), (-1, 0, 1, -1)]
U  = [tuple(1 if j == a else 0 for j in range(4)) for a in range(4)]

def mat(Mx, K): return tuple(sum(Mx[j][i] * K[j] for j in range(4)) for i in range(4))
def scale(K, l):
    for _ in range(2 * l): K = mat(M, K)
    return K
def add(A, B): return tuple(A[j] + B[j] for j in range(4))
def sub(A, B): return tuple(A[j] - B[j] for j in range(4))
def R45(K): return (-K[3], K[0], K[1], K[2])
def rot_tile(A, ab, l=0):
    a, b = ab
    Ar = R45(A)
    if b < 3: return Ar, (a + 1, b + 1)
    return sub(Ar, scale(U[0], l)), (0, a + 1)
def rotk_tile(A, ab, k, l=0):
    for _ in range(k % 8): A, ab = rot_tile(A, ab, l)
    return A, ab
def rotk_off(K, k):
    for _ in range(k % 8): K = R45(K)
    return K
def pos_exact(K):
    x = R2(0); y = R2(0)
    for j in range(4):
        x = x + E[j][0] * K[j]
        y = y + E[j][1] * K[j]
    return x, y
S2 = math.sqrt(2) / 2
EX = [(1, 0), (S2, S2), (0, 1), (-S2, S2)]
def pos(K):
    return (sum(EX[j][0] * K[j] for j in range(4)),
            sum(EX[j][1] * K[j] for j in range(4)))
def corners(A, ab, l):
    a, b = ab
    ua, ub = scale(U[a], l), scale(U[b], l)
    return (A, add(A, ua), add(A, add(ua, ub)), add(A, ub))

