CLASS_AB = {0: (0, 1), 1: (1, 3), 2: (0, 2), 3: (0, 3), 4: (0, 2), 5: (2, 3), 6: (1, 2), 7: (1, 3), 8: (0, 2), 9: (1, 3), 10: (1, 3), 11: (0, 2)}

def rosette(n):
    rv = {ab: c for c, ab in CLASS_AB.items() if ab[1] - ab[0] in (1, 3)}
    out = []
    for k in range(8):
        A, ab = rotk_tile((0, 0, 0, 0), (0, 1), k, n)
        out.append((A, ab, rv[ab], n))
    return out

def decompose(tiles_n, level):
    lo = level - 1
    children, parent_of = [], []
    for pi, (A, ab, var, l) in enumerate(tiles_n):
        for (doff, tab), v in RULE[var].items():
            children.append((add(A, scale(doff, lo)), tab, v, lo))
            parent_of.append(pi)
    recs = {}
    for pi, (A, ab, var, l) in enumerate(tiles_n):
        quad = corners(A, ab, l); a, b = ab
        for i in range(4):
            p, q = quad[i], quad[(i + 1) % 4]
            d = a if i % 2 == 0 else b
            side = 1 if i < 2 else -1
            if i >= 2: p, q = q, p
            recs.setdefault((p, q, d), {})[side] = pi
    for (P, Q, d), sides in recs.items():
        pairs = set()
        for side, pi in sides.items():
            A, ab, var, l = tiles_n[pi]
            aoff = sub(A, P)
            for _ in range(2 * lo): aoff = mat(MI, aoff)
            aoffn, _ = rotk_tile(aoff, ab, (8 - d) % 8, 0)
            key = (side, var, aoffn)
            if key in STRADDLE: pairs.add(STRADDLE[key])
        assert len(pairs) <= 1, 'straddler disagreement'
        if not pairs: continue
        pair = pairs.pop()
        for pos_off, v in zip(POS, pair):
            off, tab = rotk_tile(pos_off, (1, 3), d, 0)
            children.append((add(P, scale(off, lo)), tab, v, lo))
            parent_of.append(('edge', (P, Q, d)))
    return children, parent_of, recs

def generate(n=3):
    levels = {n: rosette(n)}
    parents = {}
    for l in range(n, 0, -1):
        ch, par, _ = decompose(levels[l], l)
        seen = set(); keep = []; kpar = []
        for t, p in zip(ch, par):
            k = (t[0], t[1])
            if k in seen: continue
            seen.add(k); keep.append(t); kpar.append(p)
        levels[l - 1] = keep
        parents[l - 1] = kpar
    return levels, parents

# ============================================================ graph helpers
def graph(tiles_geo):
    edges = set(); ang = defaultdict(int)
    for quad, ab in tiles_geo:
        a, b = ab
        units = [b - a, 4 - (b - a)]
        for k in range(4):
            p, q = quad[k], quad[(k + 1) % 4]
            edges.add((p, q) if p < q else (q, p))
            ang[quad[k]] += units[k % 2] if (b - a) != 2 else 2
    return edges, ang

def trace_loops(chosen):
    adj = defaultdict(list)
    for a, b in chosen:
        adj[a].append(b); adj[b].append(a)
    unused = set(map(frozenset, chosen))
    loops = []
    def walk(s, n):
        path = [s, n]; unused.discard(frozenset((s, n)))
        while True:
            cur, prev = path[-1], path[-2]
            step = None
            for w in adj[cur]:
                if frozenset((cur, w)) in unused:
                    step = w; break
            if step is None: return path
            unused.discard(frozenset((cur, step)))
            path.append(step)
    for v in [v for v, ns in adj.items() if len(ns) == 1]:
        for w in adj[v]:
            if frozenset((v, w)) in unused:
                loops.append((walk(v, w), False))
    while unused:
        a, b = tuple(next(iter(unused)))
        p = walk(a, b)
        loops.append((p, p[0] == p[-1]))
    return loops

def norm(e):
    a, b = e
    return (a, b) if a < b else (b, a)

# ============================================================ decoration
def decorate(level_tiles, lo, E_set):
    S = set()
    for (A, ab, v, l) in level_tiles:
        for rel in THICK[v]:
            r1, r2 = sorted(rel)
            e = norm((add(A, scale(r1, lo)), add(A, scale(r2, lo))))
            if e in E_set: S.add(e)
    recs = {}
    for (A, ab, v, l) in level_tiles:
        quad = corners(A, ab, l); a, b = ab
        for k in range(4):
            p, q = quad[k], quad[(k + 1) % 4]
            d = a if k % 2 == 0 else b
            side = 1 if k < 2 else -1
            if k >= 2: p, q = q, p
            recs.setdefault((p, q, d), {})[side] = v
    for (P, Q, d), sides in recs.items():
        if len(sides) != 2: continue
        key = (sides[1], sides[-1])
        if key not in STRIP: continue
        for rel in STRIP[key]:
            oa, ob = sorted(rel)
            e = norm((add(P, scale(rotk_off(oa, d), lo)),
                      add(P, scale(rotk_off(ob, d), lo))))
            if e in E_set: S.add(e)
    return S

def complete(S, edges, ang, eightset):
    import networkx as nx
    deg = defaultdict(int)
    for a, b in S:
        deg[a] += 1; deg[b] += 1
    D = {v for v, x in ang.items() if x == 8 and v not in eightset and deg[v] != 2}
    G = nx.Graph(); G.add_nodes_from(D)
    for e in edges:
        a, b = e
        if a in D and b in D and e not in S and a not in eightset and b not in eightset:
            G.add_edge(a, b)
    for a, b in nx.max_weight_matching(G, maxcardinality=True):
        S.add(norm((a, b)))
    return S

# ============================================================ e1 machinery
D2R = R2(3, 2)
ROTC = []
for k in range(8):
    Ax, Ay = pos_exact(rotk_off(U[0], k))
    ROTC.append((Ax, Ay))

def place(A, B, side, posmap, lvl):
    pA = pos_exact(A); pB = pos_exact(B)
    dvec = (pB[0] - pA[0], pB[1] - pA[1])
    d = None
    for k in range(8):
        ex, ey = ROTC[k]
        cr = ex * dvec[1] - ey * dvec[0]
        dt = ex * dvec[0] + ey * dvec[1]
        if cr.sign() == 0 and dt.sign() > 0:
            d = k; break
    c, s = ROTC[d]
    scl = R2(1)
    for _ in range(lvl - 1): scl = scl * D2R
    verts = []
    for (rx, ry) in REL_PATH:
        rx2, ry2 = rx, ry
        if side != SIDE0:
            rx2 = R2(3, 2) - rx2; ry2 = -ry2
        rx2 = rx2 * scl; ry2 = ry2 * scl
        K = posmap.get((c * rx2 - s * ry2 + pA[0], s * rx2 + c * ry2 + pA[1]))
        if K is None: return None
        verts.append(K)
    if side != SIDE0: verts = verts[::-1]
    return [(verts[i], verts[i + 1]) for i in range(len(verts) - 1)]

def alternates(path, S):
    want = False
    for e in path:
        if (norm(e) in S) != want: return False
        want = not want
    return True

def place_alt(A, B, side, posmap, lvl, S):
    p = place(A, B, side, posmap, lvl)
    return p if p is not None and alternates(p, S) else None

def toggle(S, path):
    for e in path:
        e = norm(e)
        if e in S: S.remove(e)
        else: S.add(e)

# ============================================================ main pipeline
def main(out='ab_hamiltonian_rainbow_wide_glow.svg'):
    t0 = time.time()
    log = lambda m: print('[%6.1fs] %s' % (time.time() - t0, m), flush=True)
    levels, parents = generate(3)
    log('generated: ' + ', '.join('L%d=%d' % (l, len(levels[l])) for l in sorted(levels)))

    tiles0 = [(corners(A, ab, 0), ab) for A, ab, v, l in levels[0]]
    tiles1 = [(corners(A, ab, 1), ab) for A, ab, v, l in levels[1]]
    edges0, ang0 = graph(tiles0)
    edges1, ang1 = graph(tiles1)
    eight0 = set()
    for quad, ab in tiles1: eight0.update(quad)
    eight1 = set()
    for A, ab, v, l in levels[2]: eight1.update(corners(A, ab, 2))
    C = (0, 0, 0, 0)
    log('graphs: %d L0 vertices' % len(ang0))

    chosen = decorate(levels[1], 0, edges0)
    chosen = complete(chosen, edges0, ang0, eight0)
    canonical = set(chosen)                     # generations reference
    S1 = decorate(levels[2], 1, edges1)
    log('decorated: e0=%d edges, S1=%d edges' % (len(chosen), len(S1)))

    # folded blue star at level 2
    rh = [(A, ab, v, l) for (A, ab, v, l) in levels[2] if C in corners(A, ab, 2)]
    adjS = defaultdict(list)
    starC = []
    for A, ab, v, l in rh:
        q = corners(A, ab, 2); i = q.index(C)
        N1, F, N2 = q[(i + 1) % 4], q[(i + 2) % 4], q[(i + 3) % 4]
        starC.append((N1, F, N2))
        adjS[N1].append(F); adjS[N2].append(F); adjS[F] += [N1, N2]
    Ffold = starC[0][1]
    cyc = []; prev, cur = None, starC[0][0]
    while True:
        cyc.append(cur)
        nxt = [w for w in adjS[cur] if w != prev and w != Ffold]
        if not nxt: break
        prev, cur = cur, nxt[0]
        if cur == starC[0][0]: break
    if cyc[-1] != starC[0][0]: cyc.append(C)
    posmap1 = {pos_exact(v): v for v in ang1}
    S1f = set(S1)
    side = 1
    for i in range(len(cyc)):
        Pv, Qv = cyc[i], cyc[(i + 1) % len(cyc)]
        p = place_alt(Pv, Qv, side, posmap1, 2, S1) or \
            place_alt(Pv, Qv, -side, posmap1, 2, S1)
        assert p, 'e2 placement failed'
        toggle(S1f, p)
        side = -side
    deg1 = defaultdict(int)
    for a, b in S1f: deg1[a] += 1; deg1[b] += 1
    assert deg1[C] == 2 and deg1[Ffold] == 0
    log('folded star threaded through the center')

    posmap0 = {pos_exact(v): v for v in ang0}
    log('posmap0 built (%d exact positions)' % len(posmap0))
    aug = 0
    for path, closed in trace_loops(sorted(S1f)):
        if not closed: continue
        verts = path[:-1]; n = len(verts)
        if n % 2: continue
        pl = []
        ok = True
        for k in range(n):
            p = place_alt(verts[k], verts[(k + 1) % n],
                          1 if k % 2 == 0 else -1, posmap0, 1, chosen)
            if p is None: ok = False; break
            pl.append(p)
        if not ok: continue
        for p in pl: toggle(chosen, p)
        aug += 1
    log('augmented %d supertile-edge rings' % aug)

    loops = trace_loops(sorted(chosen))
    big = max((p for p, c in loops if c), key=len)
    log('largest cycle: %d vertices' % (len(big) - 1))
    inwin = lambda v: abs(pos(v)[0]) <= 9 and abs(pos(v)[1]) <= 16
    others = [p for p, c in loops if c and p is not big and any(inwin(v) for v in p)]
    assert not others, 'window not single-path!'
    log('validation: exactly one cycle through the central window')

    # ---------- render ----------
    nb = len(big) - 1; verts = big[:-1]
    fx, fy = pos(Ffold)
    th = math.radians(270.0 - math.degrees(math.atan2(fy, fx)))
    c0, s0 = math.cos(th), math.sin(th)
    PR = lambda v: (c0 * pos(v)[0] - s0 * pos(v)[1],
                    s0 * pos(v)[0] + c0 * pos(v)[1])
    edepth = {}
    for p, c in trace_loops(sorted(canonical)):
        if not c: continue
        g = math.log2(len(p) - 1)
        for i in range(len(p) - 1):
            edepth[norm((p[i], p[i + 1]))] = g
    Eb = [norm((verts[i], verts[(i + 1) % nb])) for i in range(nb)]
    vinc = defaultdict(list)
    for e in Eb:
        vinc[e[0]].append(e); vinc[e[1]].append(e)
    missing = [e for e in Eb if e not in edepth]
    for _ in range(8):
        still = []
        for e in missing:
            vals = [edepth[f] for v in e for f in vinc[v] if f in edepth]
            if vals: edepth[e] = sum(vals) / len(vals)
            else: still.append(e)
        missing = still
        if not missing: break
    ge = [edepth[e] for e in Eb]
    ANCH = ['#b3342b', '#d07c3a', '#b89a3a', '#6a9a6a', '#4f7d9e', '#31445f']
    AN = [[int(h[i:i + 2], 16) / 255 for i in (1, 3, 5)] for h in ANCH]
    lv = sorted({round(g, 4) for g in ge})
    def colr(g):
        if len(lv) > 1:
            t = 0.0
            for i in range(len(lv) - 1):
                if g >= lv[i]:
                    t = (i + min(max((g - lv[i]) / (lv[i + 1] - lv[i]), 0), 1)) / (len(lv) - 1)
        else: t = 0.5
        x = t * (len(AN) - 1); i = int(min(x, len(AN) - 2)); f = x - i
        return tuple((1 - f) * AN[i][k] + f * AN[i + 1][k] for k in range(3))
    def hexc(c): return '#%02x%02x%02x' % tuple(int(round(255 * x)) for x in c)
    bright = lambda c: tuple(1 - (1 - x) * 0.40 for x in c)
    XY = [PR(v) for v in verts]
    m = 1.6
    x0 = min(p[0] for p in XY) - m; x1 = max(p[0] for p in XY) + m
    y0 = min(p[1] for p in XY) - m; y1 = max(p[1] for p in XY) + m
    Wu, Hu = x1 - x0, y1 - y0
    bnd = [i for i in range(nb) if abs(ge[i] - ge[i - 1]) > 1e-9]
    runs = []
    if not bnd: runs = [list(range(nb))]
    else:
        for k in range(len(bnd)):
            i0, i1 = bnd[k], bnd[(k + 1) % len(bnd)]
            run = []; i = i0
            while True:
                run.append(i)
                if (i + 1) % nb == i1: break
                i = (i + 1) % nb
            runs.append(run)
    def poly(run):
        pts = [XY[run[0]]] + [XY[(i + 1) % nb] for i in run]
        return ' '.join('%.3f,%.3f' % (x, -y) for x, y in pts)
    S = ['<svg xmlns="http://www.w3.org/2000/svg" viewBox="%.3f %.3f %.3f %.3f" width="1600">'
         % (x0, -y1, Wu, Hu),
         '<rect x="%.3f" y="%.3f" width="%.3f" height="%.3f" fill="black"/>' % (x0, -y1, Wu, Hu)]
    for w, cf in ((0.52, colr), (0.30, lambda g: bright(colr(g)))):
        for run in runs:
            S.append('<polyline points="%s" fill="none" stroke="%s" stroke-width="%.2f" '
                     'stroke-linejoin="round" stroke-linecap="round"/>'
                     % (poly(run), hexc(cf(ge[run[0]])), w))
    S.append('</svg>')
    open(out, 'w').write('\n'.join(S))
    log('wrote %s (%d color runs)' % (out, len(runs)))

if __name__ == '__main__':
    main(sys.argv[1] if len(sys.argv) > 1 else 'ab_hamiltonian_rainbow_wide_glow.svg')
